script:
frappe.ui.form.on("Hostel", {
    refresh(frm) {
        if (!frm.is_new()) {
            frm.add_custom_button("Wardens", function () {
                frappe.set_route("List", "Warden", { hostel: frm.doc.name });
            }, "View");

            frm.add_custom_button("Complaints", function () {
                frappe.set_route("List", "Grievance Box", { hostel: frm.doc.name });
            }, "View");
        }
    }
});
